export class YaksokSession {
  constructor() {
    this.modules = new Map()
  }
  addModule(name, code) {
    this.modules.set(name, code)
  }
  async runModule(name) {
    const code = this.modules.get(name)
    // very small emulation: if code contains a message in quotes, resolve after next tick
    if (typeof code === 'string') {
      // no-op: simulate async execution
      await new Promise((r) => setTimeout(r, 10))
      console.log('[dalbit-yaksok shim] runModule', name, code)
      return code
    }
    return undefined
  }
}

export const yaksok = new YaksokSession()
